using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ─── CalculateTotal: DataRow tests ───────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ─── CalculateTotal: DynamicData for edge cases ──────────────────────────

    public static IEnumerable<object[]> CalculateTotalEdgeCases
    {
        get
        {
            yield return new object[] { 0.01m, 1, 0.0m, 0.01m, "Minimum meaningful price" };
            yield return new object[] { 9999.99m, 100, 1.0m, 1_999_998.00m, "Large order, max tax" };
            yield return new object[] { 1.00m, 1, 0.0m, 1.00m, "Unit baseline" };
            yield return new object[] { 5.00m, 10, 0.25, 62.50m, "25% tax rate" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    // ─── CalculateTotal: Invalid inputs ──────────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative price throws")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity throws")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Negative tax throws")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax > 1 throws")]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    // ─── ApplyDiscount: DataRow tests ────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "0% discount — full price")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount — free")]
    [DataRow(59.99, 25.0, 44.9925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price with discount")]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ─── ApplyDiscount: DynamicData with method source ───────────────────────

    public static IEnumerable<object[]> GetInvalidDiscountCases()
    {
        yield return new object[] { 100.00m, -1.0m, "Negative discount" };
        yield return new object[] { 100.00m, -0.01m, "Barely negative discount" };
        yield return new object[] { 100.00m, 100.01m, "Barely over 100%" };
        yield return new object[] { 50.00m, 200.0m, "Way over 100%" };
    }

    [TestMethod]
    [DynamicData(nameof(GetInvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent, string scenario)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName, $"Failed for: {scenario}");
    }
}

